func NewQSServiceStub(
	impl IQSServiceServer,
) IQSService {
	wrapper := &qSServiceStubWrapper{impl: impl}
	stub := &QSServiceStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
